        let vec_path = staging_dir.join(format!("{entry_id}.vec"));
        if let Ok(bytes) = std::fs::read(&vec_path)
            && let Ok(floats) = bytemuck::try_cast_slice::<u8, f32>(&bytes)
        {
            entry.embedding = Some(floats.to_vec());
        }
        Ok(entry)
